python.code:
def contains_even(nums):
    for n in nums:
        if n % 2 == 0:
            return True
        return False

java.code:
boolean containsEven(int[] nums) {
    for (int n : nums) {
        if (n % 2 == 0) return true;
        return false;
    }
    return false;
}

javascript.code:
function containsEven(nums) {
  for (const n of nums) {
    if (n % 2 === 0) return true;
    return false;
  }
  return false;
}

cpp.code:
bool containsEven(int nums[], int size) {
    for (int i = 0; i < size; i++) {
        if (nums[i] % 2 == 0) return true;
        return false;
    }
    return false;
}
